import React, { useState } from 'react';
import { Bar, Pie } from 'react-chartjs-2';
import { Chart as ChartJS, ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title } from 'chart.js';
import { Bell, PlusCircle, LogOut, Menu, User, FileText, BarChart2, Settings, Home } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

// Register ChartJS components
ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

export default function Dashboard() {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [activeTab, setActiveTab] = useState('dashboard');
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  // Handle logout
  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  // Dummy data - would come from API in real implementation
  const expenseData = {
    totalExpenses: 35000,
    pendingApprovals: 5,
    approvedRequests: 12,
    rejectedRequests: 2
  };

  const recentExpenses = [
    { id: 1, date: '2023-04-12', category: 'Travel', amount: 2500, status: 'Pending' },
    { id: 2, date: '2023-04-10', category: 'Food', amount: 1000, status: 'Approved' },
    { id: 3, date: '2023-04-08', category: 'Office Supplies', amount: 1500, status: 'Approved' },
    { id: 4, date: '2023-04-05', category: 'Travel', amount: 5000, status: 'Rejected' },
    { id: 5, date: '2023-04-01', category: 'Food', amount: 800, status: 'Approved' },
  ];

  // Toggle sidebar visibility on mobile
  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  return (
    <div className="flex h-screen bg-gray-100">
      {/* Sidebar */}
      <div className={`${sidebarOpen ? 'translate-x-0' : '-translate-x-full'} fixed inset-y-0 left-0 z-30 w-64 bg-indigo-700 text-white transition-transform duration-300 md:static md:translate-x-0`}>
        <div className="flex h-16 items-center justify-center border-b border-indigo-600">
          <h1 className="text-xl font-bold">Expense Management</h1>
        </div>

        <nav className="mt-6 px-4">
          <button 
            className={`mb-3 flex w-full items-center rounded-md px-4 py-2 ${activeTab === 'dashboard' ? 'bg-indigo-800' : 'hover:bg-indigo-600'}`}
            onClick={() => setActiveTab('dashboard')}
          >
            <Home className="mr-3" size={20} />
            Dashboard
          </button>

          <button 
            className={`mb-3 flex w-full items-center rounded-md px-4 py-2 ${activeTab === 'expenses' ? 'bg-indigo-800' : 'hover:bg-indigo-600'}`}
            onClick={() => setActiveTab('expenses')}
          >
            <FileText className="mr-3" size={20} />
            My Expenses
          </button>

          <button 
            className={`mb-3 flex w-full items-center rounded-md px-4 py-2 ${activeTab === 'reports' ? 'bg-indigo-800' : 'hover:bg-indigo-600'}`}
            onClick={() => setActiveTab('reports')}
          >
            <BarChart2 className="mr-3" size={20} />
            Reports
          </button>

          <button 
            className={`mb-3 flex w-full items-center rounded-md px-4 py-2 ${activeTab === 'settings' ? 'bg-indigo-800' : 'hover:bg-indigo-600'}`}
            onClick={() => setActiveTab('settings')}
          >
            <Settings className="mr-3" size={20} />
            Settings
          </button>

          <button 
            className="mt-6 flex w-full items-center rounded-md px-4 py-2 text-red-300 hover:bg-indigo-600"
            onClick={handleLogout}
          >
            <LogOut className="mr-3" size={20} />
            Logout
          </button>
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex flex-1 flex-col overflow-hidden">
        {/* Header */}
        <header className="flex h-16 items-center justify-between bg-white px-6 shadow">
          <button className="rounded-md p-1 focus:outline-none md:hidden" onClick={toggleSidebar}>
            <Menu size={24} />
          </button>

          <div className="flex items-center">
            <button className="mr-4 rounded-full p-1 hover:bg-gray-100">
              <Bell size={20} />
            </button>
            <div className="flex items-center">
              <div className="h-8 w-8 rounded-full bg-indigo-500 flex items-center justify-center text-white">
                <User size={18} />
              </div>
              <span className="ml-2 font-medium">{user?.fullName || 'User'}</span>
            </div>
          </div>
        </header>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto p-6">
          <div className="mb-6 flex flex-wrap items-center justify-between">
            <h1 className="text-2xl font-bold">Dashboard</h1>
            <button className="flex items-center rounded-md bg-indigo-600 px-4 py-2 text-white hover:bg-indigo-700">
              <PlusCircle className="mr-2" size={18} />
              New Expense
            </button>
          </div>

          {/* Metrics Cards */}
          <div className="grid grid-cols-1 gap-6 mb-6 sm:grid-cols-2 lg:grid-cols-4">
            <div className="bg-white p-6 rounded-lg shadow">
              <div className="flex items-center">
                <div className="p-3 rounded-full bg-indigo-100 text-indigo-500">
                  <FileText size={24} />
                </div>
                <div className="ml-4">
                  <p className="text-sm text-gray-500 mb-1">Total Expenses</p>
                  <h3 className="text-xl font-semibold">₹{expenseData.totalExpenses.toLocaleString()}</h3>
                </div>
              </div>
            </div>

            <div className="bg-white p-6 rounded-lg shadow">
              <div className="flex items-center">
                <div className="p-3 rounded-full bg-yellow-100 text-yellow-500">
                  <Bell size={24} />
                </div>
                <div className="ml-4">
                  <p className="text-sm text-gray-500 mb-1">Pending Approvals</p>
                  <h3 className="text-xl font-semibold">{expenseData.pendingApprovals}</h3>
                </div>
              </div>
            </div>

            <div className="bg-white p-6 rounded-lg shadow">
              <div className="flex items-center">
                <div className="p-3 rounded-full bg-green-100 text-green-500">
                  <Bell size={24} />
                </div>
                <div className="ml-4">
                  <p className="text-sm text-gray-500 mb-1">Approved Requests</p>
                  <h3 className="text-xl font-semibold">{expenseData.approvedRequests}</h3>
                </div>
              </div>
            </div>

            <div className="bg-white p-6 rounded-lg shadow">
              <div className="flex items-center">
                <div className="p-3 rounded-full bg-red-100 text-red-500">
                  <Bell size={24} />
                </div>
                <div className="ml-4">
                  <p className="text-sm text-gray-500 mb-1">Rejected Requests</p>
                  <h3 className="text-xl font-semibold">{expenseData.rejectedRequests}</h3>
                </div>
              </div>
            </div>
          </div>

          {/* Charts Section */}
          <div className="grid grid-cols-1 gap-6 mb-6 lg:grid-cols-2">
            <div className="bg-white p-6 rounded-lg shadow">
              <h2 className="text-lg font-semibold mb-4">Monthly Spending</h2>
              <Bar
                data={{
                  labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
                  datasets: [
                    {
                      label: 'Expenses',
                      data: [5000, 7000, 4500, 8500, 6000, 9000],
                      backgroundColor: '#6366f1',
                    },
                  ],
                }}
                options={{
                  responsive: true,
                  maintainAspectRatio: false,
                  plugins: {
                    legend: {
                      display: false,
                    },
                  },
                }}
                height={300}
              />
            </div>

            <div className="bg-white p-6 rounded-lg shadow">
              <h2 className="text-lg font-semibold mb-4">Expense Categories</h2>
              <Pie
                data={{
                  labels: ['Travel', 'Food', 'Office Supplies', 'Utilities', 'Others'],
                  datasets: [
                    {
                      data: [8000, 3500, 2500, 1500, 1000],
                      backgroundColor: ['#6366f1', '#f97316', '#10b981', '#0ea5e9', '#8b5cf6'],
                    },
                  ],
                }}
                options={{
                  responsive: true,
                  maintainAspectRatio: false,
                }}
                height={300}
              />
            </div>
          </div>

          {/* Recent Expenses Table */}
          <div className="bg-white p-6 rounded-lg shadow">
            <h2 className="text-lg font-semibold mb-4">Recent Expenses</h2>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50 text-left text-xs uppercase tracking-wider text-gray-500">
                  <tr>
                    <th className="px-6 py-3">Date</th>
                    <th className="px-6 py-3">Category</th>
                    <th className="px-6 py-3">Amount</th>
                    <th className="px-6 py-3">Status</th>
                    <th className="px-6 py-3">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200">
                  {recentExpenses.map((expense) => (
                    <tr key={expense.id} className="hover:bg-gray-50">
                      <td className="whitespace-nowrap px-6 py-4">{expense.date}</td>
                      <td className="whitespace-nowrap px-6 py-4">{expense.category}</td>
                      <td className="whitespace-nowrap px-6 py-4">₹{expense.amount}</td>
                      <td className="whitespace-nowrap px-6 py-4">
                        <span className={`inline-flex rounded-full px-2 text-xs font-semibold leading-5 ${
                          expense.status === 'Approved' ? 'bg-green-100 text-green-800' : 
                          expense.status === 'Pending' ? 'bg-yellow-100 text-yellow-800' : 
                          'bg-red-100 text-red-800'
                        }`}>
                          {expense.status}
                        </span>
                      </td>
                      <td className="whitespace-nowrap px-6 py-4">
                        <button className="text-indigo-600 hover:text-indigo-900">View</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}
